diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..b5104b6cabdf 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2261,8 +2261,73 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     Intrinsic::ID InvID = getInverseMinMaxIntrinsic(MinMax->getIntrinsicID());
     Function *F = Intrinsic::getOrInsertDeclaration(I.getModule(), InvID, Ty);
     return CallInst::Create(F, {Op0, Z});
+    return CallInst::Create(F, {Op0, Z});
   }

+  // sub(smin(X + C, Y), smin(X, Y)) --> C if X < Y else 0
+  // sub(smax(X + C, Y), smax(X, Y)) --> C if X > Y else 0
+  // sub(umin(X + C, Y), umin(X, Y)) --> C if X < Y else 0
+  // sub(umax(X + C, Y), umax(X, Y)) --> C if X > Y else 0
+  // Where C is a constant.
+  // Also handle or disjoint (which is equivalent to add for power-of-2 constants):
+  // sub(smin(X | C, Y), smin(X, Y)) --> C if X < Y else 0 (when C is power-of-2 and or is disjoint)
+  const APInt *C;
+  auto *MinMax0 = dyn_cast<MinMaxIntrinsic>(Op0);
+  if (MinMax0 && MinMax0->getIntrinsicID() == MinMax->getIntrinsicID() &&
+      MinMax->hasOneUse()) {
+    Value *X0 = MinMax0->getLHS();
+    Value *Y0 = MinMax0->getRHS();
+    Value *X1 = MinMax->getLHS();
+    Value *Y1 = MinMax->getRHS();
+    // Check if Y operands match
+    if (Y0 == Y1) {
+      // Check if X0 = X1 + C (with appropriate overflow flags)
+      if (match(X0, m_Add(m_Specific(X1), m_APInt(C)))) {
+        auto *Add = cast<BinaryOperator>(X0);
+        bool IsSigned = MinMax->isSigned();
+        bool HasNoWrap = IsSigned ? Add->hasNoSignedWrap()
+                                  : Add->hasNoUnsignedWrap();
+        if (HasNoWrap) {
+          // Result is: select(X cmp Y, C, 0)
+          // For smin/umin: if X < Y, result is (X+C) - X = C, else Y - Y = 0
+          // For smax/umax: if X > Y, result is (X+C) - X = C, else Y - Y = 0
+          Intrinsic::ID ID = MinMax->getIntrinsicID();
+          bool IsMax = (ID == Intrinsic::smax || ID == Intrinsic::umax);
+          CmpInst::Predicate Pred = IsSigned
+                                        ? (IsMax ? CmpInst::ICMP_SGT
+                                                 : CmpInst::ICMP_SLT)
+                                        : (IsMax ? CmpInst::ICMP_UGT
+                                                 : CmpInst::ICMP_ULT);
+          Value *Cmp = Builder.CreateICmp(Pred, X1, Y1);
+          Value *Zero = ConstantInt::get(Ty, 0);
+          Value *CVal = ConstantInt::get(Ty, *C);
+          return SelectInst::Create(Cmp, CVal, Zero);
+        }
+      }
+      // Check if X0 = X1 | C where or is disjoint and C is a constant
+      // This is equivalent to X1 + C when C is a power of 2 and the or is disjoint
+      if (match(X0, m_DisjointOr(m_Specific(X1), m_APInt(C)))) {
+        // For smin/smax, we need to ensure the result is correct
+        // X | C = X + C when C is a power of 2 and the bits don't overlap
+        // This is guaranteed by the disjoint flag
+        // Result is: select(X cmp Y, C, 0)
+        Intrinsic::ID ID = MinMax->getIntrinsicID();
+        bool IsSigned = MinMax->isSigned();
+        bool IsMax = (ID == Intrinsic::smax || ID == Intrinsic::umax);
+        CmpInst::Predicate Pred = IsSigned
+                                      ? (IsMax ? CmpInst::ICMP_SGT
+                                               : CmpInst::ICMP_SLT)
+                                      : (IsMax ? CmpInst::ICMP_UGT
+                                               : CmpInst::ICMP_ULT);
+        Value *Cmp = Builder.CreateICmp(Pred, X1, Y1);
+        Value *Zero = ConstantInt::get(Ty, 0);
+        Value *CVal = ConstantInt::get(Ty, *C);
+        return SelectInst::Create(Cmp, CVal, Zero);
+      }
+    }
+  }
+
+
   return nullptr;
 }

